<template>
  <div class="page-wxapp-policy">
    <div class="hd">
      用戶隱私保護指引
    </div>
    <div class="bd">
      <h3>《{{ weappName }}小程序隱私保護指引》</h3>
      <p>
        本指引是{{
          weappName
        }}小程序開發者商派軟件有限公司（以下簡稱“開發者”）為處理你的個人訊息而製定。
      </p>
      <br>
      <h4>1. 開發者處理的訊息</h4>
      <p>根據法律規定，開發者僅處理實現小程序功能所必要的訊息。</p>
      <div class="policy-container mtp-10">
        <!-- {{policyObject}} -->
        <div
          v-for="(key, index) in privacyList"
          :key="`policy-item__${index}`"
          class="policy-item"
        >
          為了
          <el-input
            v-model="policyObject[key]"
            size="small"
            placeholder="請輸入內容"
            style="width: 480px"
            maxlength="30"
            show-word-limit
          />，開發者將在獲取你的明示同意後，收集你的{{ getPrivacyDesc(key) }}
        </div>
      </div>
      <br>
      <h4>2. 第三方服務商訊息</h4>
      <p>
        {{
          weappName
        }}小程序由商派軟件有限公司代為開發，開發者保證，商派軟件有限公司將在本指引規定範圍內處理你的個人訊息。
      </p>
      <br>
      <h4>3. 你的權益</h4>
      <p>
        3.1
        關於收集你的位置訊息，你可以通過以下路徑：小程序主頁右上角..."-”設置”-點擊特定訊息-點擊"不允許”，撤回對開發者的授權。
      </p>
      <p>
        3.2 關於收集你的微信昵稱、頭像、收集你的地址，你可以通過以下路徑:小程序主頁右上角..."
        -“設置"一“小程序已獲取的訊息"-點擊特定訊息-點擊“通知開發者刪除"，開發者承諾收到通知後將刪除訊息。
      </p>
      <p>
        3.3 關於你的個人訊息，
        你可以通過以下方式與開發者聯絡，行使查閱、複製、更正、刪除等法定權利。
      </p>
      <div class="mtp-10">
        <el-input
          v-model="contactValue"
          size="small"
          :placeholder="`請輸入${contactOptions[contact]}`"
          class="input-with-select"
          style="width: 300px"
        >
          <el-select
            slot="prepend"
            v-model="contact"
            placeholder="請選擇"
          >
            <el-option
              v-for="(value, key) in contactOptions"
              :key="`option-item__${key}`"
              :label="value"
              :value="key"
            />
          </el-select>
        </el-input>
      </div>
      <br>
      <h4>4. 開發者對訊息的存儲</h4>
      <!-- <p>{{weappName}}小程序由商派軟件有限公司代為開發，開發者保證，商派軟件有限公司將在本指引規定範圍內處理你的個人訊息。</p> -->
      <div class="mtp-10">
        <div>
          <el-radio
            v-model="storeType"
            label="1"
          >
            固定存儲期限
          </el-radio>
          <el-date-picker
            v-model="ownerSetting.store_expire_timestamp"
            type="date"
            size="small"
            placeholder="選擇日期"
          />
        </div>
        <div class="mtp-10">
          <el-radio
            v-model="storeType"
            label="2"
          >
            開發者承諾，除法律法規另有規定外，開發者對你的訊息的儲存期限應當為實現處理目的所必要的最短時間。
          </el-radio>
        </div>
      </div>
      <br>
      <h4>5. 訊息的使用規則</h4>
      <p>5.1 開發者將會在本指引所明示的用途內使用收集的訊息</p>
      <p>
        5.2 如開發者使用你的訊息超出本指引目的或合理範圍，開發者必須在變更使用目的或範圍前，再次以
      </p>
      <div class="mtp-10">
        <el-input
          v-model="ownerSetting.notice_method"
          placeholder="請填寫通知方式"
          size="small"
          style="width: 300px"
        />
        方式告知並征得你的明示同意。
      </div>
      <br>
      <h4>6. 訊息對外提供</h4>
      <p>
        6.1
        開發者承諾，不會主動共享或轉讓你的訊息至任何第三方，如存在確需共享或轉讓時，開發者應當直接征得或確認第三方征得你的單獨同意。
      </p>
      <p>
        6.2
        開發者承諾，不會對外公開披露你的訊息，如必須公開披露時，開發者應當向你告知公開披露的目的、披露訊息的類型及可能涉及的訊息，並征得你的單獨同意。
      </p>
      <br>
      <h4>7. 補充文檔</h4>
      <p>了解更多個人訊息處理規則可查看補充文檔，穩定格式隻支持.txt，大小不超過100kb</p>
      <div class="upload-block">
        <el-upload
          action=""
          :on-change="onChangeUpload"
          :auto-upload="false"
          :show-file-list="false"
          style="display: inline-block; margin-right: 20px"
        >
          <el-button type="primary">
            點擊上傳
          </el-button>
        </el-upload>
        <span>{{ fileName }}</span>
      </div>
    </div>
    <div class="ft">
      <el-button
        type="primary"
        @click="savePolicyConfig"
      >
        確定並生成協議
      </el-button>
    </div>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
export default {
  name: '',
  data () {
    return {
      wxapp_id: '',
      weappName: '',
      privacyList: [],
      privacyDescList: [],
      settingList: [],
      policyObject: {},
      contact: 'contact_phone',
      contactValue: '',
      storeType: '1',
      fileName: '',
      contactOptions: {
        'contact_phone': '手機號碼',
        'contact_email': '郵箱',
        'contact_qq': 'QQ號',
        'contact_weixin': '微信號'
      },
      ownerSetting: {
        'contact_phone': '',
        'contact_email': '',
        'contact_qq': '',
        'contact_weixin': '',
        'store_expire_timestamp': '',
        'ext_file_media_id': '',
        'notice_method': ''
      }
    }
  },
  created () {
    if (this.$route.query && this.$route.query.app_id) {
      this.wxapp_id = this.$route.query.app_id
    }
    if (this.$route.query && this.$route.query.nick_name) {
      this.weappName = this.$route.query.nick_name
    }
    this.getPolicyConfig()
  },
  mounted () {
    if (this.$route.query && this.$route.query.app_id) {
      this.wxapp_id = this.$route.query.app_id
    }
    if (this.$route.query && this.$route.query.nick_name) {
      this.weappName = this.$route.query.nick_name
    }
  },
  methods: {
    async getPolicyConfig () {
      const { privacy_desc, setting_list, owner_setting, privacy_list } =
        await this.$api.policy.getPolicyConfig({
          wxaAppId: this.wxapp_id
        })
      this.privacyDescList = privacy_desc.privacy_desc_list
      this.settingList = setting_list
      this.ownerSetting = owner_setting
      this.privacyList = privacy_list

      if (this.ownerSetting.store_expire_timestamp) {
        this.storeType = '1'
      } else {
        this.storeType = '2'
      }
      if (this.ownerSetting.contact_email) {
        this.contact = 'contact_email'
        this.contactValue = this.ownerSetting.contact_email
      }

      if (this.ownerSetting.contact_phone) {
        this.contact = 'contact_phone'
        this.contactValue = this.ownerSetting.contact_phone
      }

      if (this.ownerSetting.contact_qq) {
        this.contact = 'contact_qq'
        this.contactValue = this.ownerSetting.contact_qq
      }

      if (this.ownerSetting.contact_weixin) {
        this.contact = 'contact_weixin'
        this.contactValue = this.ownerSetting.contact_weixin
      }

      // demo
      // this.privacyList = [
      //   "UserInfo",
      //   "Location",
      //   "Address",
      //   "Invoice",
      //   "RunData",
      //   "Record",
      //   "Album",
      //   "Camera",
      //   "Contact",
      //   "AlbumWriteOnly",
      //   "BlueTooth",
      //   "CalendarWriteOnly",
      //   "MessageFile"
      // ]
      this.privacyList.forEach((key) => {
        const fd = this.settingList.find((item) => item.privacy_key == key)
        this.$set(this.policyObject, key, fd ? fd.privacy_text : '')
      })
    },
    async onChangeUpload (file) {
      const { ext_file_media_id } = await this.$api.policy.uploadPolicyFile({
        wxaAppId: this.wxapp_id,
        isUploadFile: true,
        file: file.raw
      })
      this.fileName = file.name
      this.$message.success('文件上傳成功')
      this.ownerSetting.ext_file_media_id = ext_file_media_id
    },
    async savePolicyConfig () {
      if (this.storeType == '2') {
        this.ownerSetting.store_expire_timestamp = ''
      }
      if (this.contact == 'contact_phone') {
        this.ownerSetting = {
          ...this.ownerSetting,
          contact_phone: this.contactValue,
          contact_email: '',
          contact_qq: '',
          contact_weixin: ''
        }
      }
      if (this.contact == 'contact_email') {
        this.ownerSetting = {
          ...this.ownerSetting,
          contact_phone: '',
          contact_email: this.contactValue,
          contact_qq: '',
          contact_weixin: ''
        }
      }
      if (this.contact == 'contact_qq') {
        this.ownerSetting = {
          ...this.ownerSetting,
          contact_phone: '',
          contact_email: '',
          contact_qq: this.contactValue,
          contact_weixin: ''
        }
      }
      if (this.contact == 'contact_weixin') {
        this.ownerSetting = {
          ...this.ownerSetting,
          contact_phone: '',
          contact_email: '',
          contact_qq: '',
          contact_weixin: this.contact_weixin
        }
      }
      let settingList = []
      Object.keys(this.policyObject).forEach((key) => {
        settingList.push({
          privacy_key: key,
          privacy_text: this.policyObject[key]
        })
      })

      const fd = settingList.find((item) => item.privacy_text == '')
      if (fd) {
        this.$message.error(`請填寫收集${this.getPrivacyDesc(fd.privacy_key)}的原因`)
        return
      }
      if (!this.ownerSetting.notice_method) {
        this.$message.error('請填寫通知方式')
        return
      }

      await this.$api.policy.savePolicyConfig({
        wxaAppId: this.wxapp_id,
        owner_setting: JSON.stringify(this.ownerSetting),
        setting_list: JSON.stringify(settingList)
      })
      this.$message.success('儲存成功')
      this.$router.go(-1)
    },
    getPrivacyDesc (key) {
      const fd = this.privacyDescList.find((item) => item.privacy_key == key)
      return fd ? fd.privacy_desc : ''
    }
  }
}
</script>
